class InferenceTimeScalingAgent:
    def solve_with_scaling(self, problem, max_budget=100):
        difficulty = self.estimate_difficulty(problem)
        solutions = []

        # Low budget: multiple attempts
        if difficulty >= 10:
            solutions.extend(self.multiple_attempts(problem, n=5))

        # Medium: deep reasoning with verification
        if difficulty >= 30:
            solutions.append(self.deep_reasoning(problem))

        # High: solution space search
        if difficulty >= 50:
            solutions.append(self.solution_search(problem))

        return self.select_best_solution(solutions)
